    } = await req.json();
    const TARGET_REPO = repo_name || DEFAULT_REPO;
    await ensureBranchExists(TARGET_REPO);

    // 1. INIT
    if (action === "init") {
        const scope = project_path || "";
        const historyLimit = 20;
        const logLimit = 20;
