 877 | function findBlockRobust(originalContent: string, searchBlock: string): { start: number; end: number } | null {
 878 |   if (!searchBlock || !originalContent) return null;
 879 | 
 880 |   const createFingerprint = (str: string) => {
 881 |     let clean = "";
 882 |     const map: number[] = [];
 883 |     for (let i = 0; i < str.length; i++) {
 884 |       if (!/\s/.test(str[i])) {
 885 |         clean += str[i];
 886 |         map.push(i);
 887 |       }
 888 |     }
 889 |     return { clean, map };
 890 |   };
