 892 |   const fileFP = createFingerprint(originalContent);
 893 |   const searchFP = createFingerprint(searchBlock);
 894 | 
 895 |   // 1. Strict Structural Match
 896 |   let matchIndex = fileFP.clean.indexOf(searchFP.clean);
 897 | 
 898 |   // 2. Quote-Agnostic Fallback (e.g. " vs ')
 899 |   if (matchIndex === -1) {
 900 |     const normalizeQuotes = (s: string) => s.replace(/['"`]/g, '"');
 901 |     matchIndex = normalizeQuotes(fileFP.clean).indexOf(normalizeQuotes(searchFP.clean));
 902 |   }
 903 | 
 904 |   if (matchIndex === -1) return null;
 905 | 
 906 |   const start = fileFP.map[matchIndex];
 907 |   const end = fileFP.map[matchIndex + searchFP.clean.length - 1] + 1;
